sql:
SELECT AVG(duration) AS average_duration
FROM music_videos
WHERE year = 2010;

SELECT duration, title 
FROM music_videos 
ORDER BY duration DESC;

SELECT MAX(duration) AS max_duration
FROM music_videos
WHERE year >= strftime('%Y', 'now') - 5;

SELECT MAX(total_views) AS max_total_views
FROM (
  SELECT SUM(views) AS total_views
  FROM video_usage_stats
  GROUP BY video_id
) AS subquery;

external_knowledge:
- "masterminds" refers to the directors of the music videos; 
- "most viewed" implies the videos with the highest average views; 
- "stars" refers to the performers in the videos; 
- "cherished" means accessed or viewed.

sql:
SELECT mv.title, mv.year, mv.rating, s.name AS style_name
FROM music_videos AS mv
JOIN styles AS s ON mv.style_id = s.style_id;

SELECT AVG(rating) AS average_rating, year
FROM music_videos
GROUP BY year;
